ruleSearch.bookList:
.searchTopic
<js>
result.toArray().slice(0,3).map(o=>{
    var url = baseUrl.match(/(.+\/\/.+?\/)/)[1] + o.select('a').attr('href');
    var J = org.jsoup.Jsoup.parse(java.ajax(url));
    var o = selector =>String(J.select(selector).text());
    return {
        name: o('h1').match(/《(.+)》/)[1].replace(/\s.*/,''),
        author: o('#xxlist li:eq(4)').replace(/.*：/,''),
        kind: o('#xxlist li:eq(1)').replace(/.*：/,'').replace(/\s-\s/,','),
        wordCount: o('#xxlist li:eq(3)').replace(/.*：/,''),
        latest: o('#xxlist li:eq(6)'),
        intro: o('.con_text p'),
        cover: J.select('.con_text img').attr('src'),
        url: url,
    }
});
</js>

ruleToc.chapterList:
@js:list = [];
if (baseUrl.match(/id/)) {
    p = result.match(/=(\d+)">最后1页/)[1];
    for (i = 0; i <= p; i++) {
        list.push({
            n: '第' + [i + 1] + '页',
            u: baseUrl.replace(/,.*$/, '&yeshu=' + i + ',{charset:"gbk"}')
        })
    }
} else list.push({
    n: '空',
    u: ''
});
list
